#include <stdio.h>
#include <math.h>

// Device function: f(x) = x^2 (example integrand)
__device__ double f(double x) {
 return x * x;
}

// Kernel V3: Warp unrolling with volatile
__global__ void trapKernelV3(double a, double h, int n, double* partialSums) {
 // Shared memory for reduction
 extern __shared__ double sdata[];

 int tid = threadIdx.x;
 int i = threadIdx.x + blockIdx.x * blockDim.x;

 // Phase 1: Each thread computes its contribution
 double mySum = 0.0;
 if (i <= n) {
 double x_i = a + i * h;
 mySum = f(x_i);
 // Multiply endpoints by 0.5 (trapezoidal rule)
 if (i == 0 || i == n) {
 mySum *= 0.5;
 }
 }

 sdata[tid] = mySum;
 __syncthreads();

 // Phase 2: Tree reduction with sync (multiple warps active)
 // Continue until stride <= 32 (single warp)
 for (unsigned int s = blockDim.x / 2; s > 32; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __syncthreads(); // Need sync when multiple warps are active
 }

 // Phase 3: Warp-level reduction (NO synchronization needed)
 // All active threads are now in warp 0, they execute in lockstep
 if (tid < 32) {
 // volatile prevents compiler from caching in registers
 volatile double* vsdata = sdata;

 // Manually unroll the last 6 reductions
 vsdata[tid] += vsdata[tid + 32];
 vsdata[tid] += vsdata[tid + 16];
 vsdata[tid] += vsdata[tid + 8];
 vsdata[tid] += vsdata[tid + 4];
 vsdata[tid] += vsdata[tid + 2];
 vsdata[tid] += vsdata[tid + 1];
 }

 // Write block result
 if (tid == 0) {
 partialSums[blockIdx.x] = sdata[0];
 }
}

// Host function to launch the kernel
double trapezoidalCUDA(double a, double b, int n) {
 double h = (b - a) / n;

 int blockSize = 256; // 8 warps per block
 int gridSize = (n + blockSize - 1) / blockSize;

 double *d_partialSums;
 cudaMalloc(&d_partialSums, gridSize * sizeof(double));

 // Shared memory: blockSize doubles
 int sharedMemSize = blockSize * sizeof(double);

 trapKernelV3<<<gridSize, blockSize, sharedMemSize>>>(a, h, n, d_partialSums);

 // Copy results back to host
 double* h_partialSums = (double*)malloc(gridSize * sizeof(double));
 cudaMemcpy(h_partialSums, d_partialSums, gridSize * sizeof(double), cudaMemcpyDeviceToHost);

 // Final reduction on host
 double totalSum = 0.0;
 for (int i = 0; i < gridSize; i++) {
 totalSum += h_partialSums[i];
 }

 totalSum *= h; // Multiply by step size

 free(h_partialSums);
 cudaFree(d_partialSums);

 return totalSum;
}

int main() {
 double a = 0.0, b = 1.0;
 int n = 1000000;

 double result = trapezoidalCUDA(a, b, n);
 printf("Result: %.10f\n", result);
 printf("Exact: %.10f\n", 1.0/3.0);

 return 0;
}

#include <stdio.h>
#include <math.h>

#define MAX_BLOCK_SIZE 1024

// Device function: f(x) = sin(x) (example integrand)
__device__ double f(double x) {
 return sin(x);
}

// Warp-level reduction using shuffle instructions
// This runs entirely in registers - no shared memory needed!
__device__ double warpReduceSum(double val) {
 // __shfl_down_sync: thread i gets value from thread i + delta
 // mask 0xFFFFFFFF means all 32 threads in warp participate

 val += __shfl_down_sync(0xFFFFFFFF, val, 16); // Warp width is 32
 val += __shfl_down_sync(0xFFFFFFFF, val, 8);
 val += __shfl_down_sync(0xFFFFFFFF, val, 4);
 val += __shfl_down_sync(0xFFFFFFFF, val, 2);
 val += __shfl_down_sync(0xFFFFFFFF, val, 1);

 // Thread 0 (lane 0) of the warp now holds the sum
 return val;
}

// Optimized kernel using two-phase reduction
__global__ void trapKernelV4(double a, double h, int n, double* partialSums) {
 // Shared memory only for warp-level results (much smaller!)
 extern __shared__ double warpResults[];

 int tid = threadIdx.x;
 int warpId = tid / 32; // Which warp am I in?
 int laneId = tid % 32; // Position within warp (0-31)

 // Phase 1: Each thread computes its contribution
 int i = tid + blockIdx.x * blockDim.x;
 double mySum = 0.0;

 if (i <= n) {
 double x_i = a + i * h;
 mySum = f(x_i);
 if (i == 0 || i == n) {
 mySum *= 0.5;
 }
 }

 // Phase 2: Intra-warp reduction using shuffles
 // Each warp reduces its 32 values to 1 value
 double warpSum = warpReduceSum(mySum);

 // Phase 3: Write warp result to shared memory
 // Only lane 0 of each warp writes
 if (laneId == 0) {
 warpResults[warpId] = warpSum;
 }

 // Single synchronization - wait for all warps to write their results
 __syncthreads();

 // Phase 4: Final warp reduces all warp sums
 // Only the first warp does this
 if (warpId == 0) {
 // Load warp results (or 0 if this lane has no warp)
 double val = (laneId < blockDim.x / 32) ? warpResults[laneId] : 0.0;

 // Use warp shuffle again for final reduction
 double blockSum = warpReduceSum(val);

 // Thread 0 writes the block result
 if (laneId == 0) {
 partialSums[blockIdx.x] = blockSum;
 }
 }
}

// Host function
double trapezoidalCUDA(double a, double b, int n) {
 double h = (b - a) / n;

 int blockSize = 256; // 8 warps
 int gridSize = (n + blockSize) / blockSize;

 // Shared memory: only for warp results (blockSize/32 entries)
 int sharedMemSize = (blockSize / 32) * sizeof(double);

 double *d_partialSums;
 cudaMalloc(&d_partialSums, gridSize * sizeof(double));

 trapKernelV4<<<gridSize, blockSize, sharedMemSize>>>(a, h, n, d_partialSums);

 // Copy and reduce on host
 double* h_results = (double*)malloc(gridSize * sizeof(double));
 cudaMemcpy(h_results, d_partialSums, gridSize * sizeof(double), cudaMemcpyDeviceToHost);

 double totalSum = 0.0;
 for (int i = 0; i < gridSize; i++) {
 totalSum += h_results[i];
 }
 totalSum *= h;

 free(h_results);
 cudaFree(d_partialSums);

 return totalSum;
}

int main() {
 double a = 0.0, b = 3.14159265;
 int n = 10000000;

 double result = trapezoidalCUDA(a, b, n);
 double exact = -cos(b) + cos(a); // Integral of sin(x) = -cos(x)

 printf("CUDA Result: %.10f\n", result);
 printf("Exact: %.10f\n", exact);
 printf("Error: %.10e\n", fabs(result - exact));

 return 0;
}

#include <stdio.h>
#include <cuda.h>

// Test function: f(x) = x^3
__device__ double f(double x) {
 return x * x * x;
}

// VERSION 1: Naive tree reduction (synchronize every step)
__global__ void trapKernelV1(double a, double h, int n, double* partialSums) {
 extern __shared__ double sdata[];
 int tid = threadIdx.x;
 int i = threadIdx.x + blockIdx.x * blockDim.x;

 double mySum = (i <= n) ? f(a + i * h) : 0.0;
 if (i == 0 || i == n) mySum *= 0.5;

 sdata[tid] = mySum;
 __syncthreads();

 // Full tree reduction - __syncthreads() EVERY iteration
 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 __syncthreads(); // 8 calls for 256 threads
 }

 if (tid == 0) partialSums[blockIdx.x] = sdata[0];
}

// VERSION 2: Volatile warp unrolling
__global__ void trapKernelV2(double a, double h, int n, double* partialSums) {
 extern __shared__ double sdata[];
 int tid = threadIdx.x;
 int i = threadIdx.x + blockIdx.x * blockDim.x;

 double mySum = (i <= n) ? f(a + i * h) : 0.0;
 if (i == 0 || i == n) mySum *= 0.5;

 sdata[tid] = mySum;
 __syncthreads();

 // Synchronized phase (multiple warps)
 for (unsigned int s = blockDim.x / 2; s > 32; s >>= 1) {
 if (tid < s) sdata[tid] += sdata[tid + s];
 __syncthreads();
 }

 // Unrolled warp phase (no sync needed)
 if (tid < 32) {
 volatile double* vsdata = sdata;
 vsdata[tid] += vsdata[tid + 32];
 vsdata[tid] += vsdata[tid + 16];
 vsdata[tid] += vsdata[tid + 8];
 vsdata[tid] += vsdata[tid + 4];
 vsdata[tid] += vsdata[tid + 2];
 vsdata[tid] += vsdata[tid + 1];
 }

 if (tid == 0) partialSums[blockIdx.x] = sdata[0];
}

// VERSION 3: Warp shuffle two-phase
__device__ double warpReduceSum(double val) {
 val += __shfl_down_sync(0xFFFFFFFF, val, 16);
 val += __shfl_down_sync(0xFFFFFFFF, val, 8);
 val += __shfl_down_sync(0xFFFFFFFF, val, 4);
 val += __shfl_down_sync(0xFFFFFFFF, val, 2);
 val += __shfl_down_sync(0xFFFFFFFF, val, 1);
 return val;
}

__global__ void trapKernelV3(double a, double h, int n, double* partialSums) {
 extern __shared__ double warpResults[];
 int tid = threadIdx.x;
 int warpId = tid / 32;
 int laneId = tid % 32;

 int i = tid + blockIdx.x * blockDim.x;
 double mySum = (i <= n) ? f(a + i * h) : 0.0;
 if (i == 0 || i == n) mySum *= 0.5;

 // Phase 1: Warp shuffle reduction
 double warpSum = warpReduceSum(mySum);

 // Phase 2: Store warp results
 if (laneId == 0) warpResults[warpId] = warpSum;
 __syncthreads();

 // Phase 3: Final warp reduces
 if (warpId == 0) {
 double val = (laneId < blockDim.x / 32) ? warpResults[laneId] : 0.0;
 double blockSum = warpReduceSum(val);
 if (laneId == 0) partialSums[blockIdx.x] = blockSum;
 }
}

// Utility to print kernel configuration
void printKernelStats(int blockSize, int gridSize) {
 int numWarps = blockSize / 32;
 int v1_syncs = 0;
 for (int s = blockSize/2; s > 0; s >>= 1) v1_syncs++;

 printf("Block Size: %d threads (%d warps)\n", blockSize, numWarps);
 printf("Grid Size: %d blocks\n", gridSize);
 printf("V1 (naive): %d __syncthreads() calls per block\n", v1_syncs);
 printf("V2 (volatile): %d __syncthreads() calls per block\n", numWarps - 1);
 printf("V3 (shuffle): 1 __syncthreads() call per block\n");
 printf("Shared Memory: V1/V2 = %d bytes, V3 = %d bytes\n",
 blockSize * 8, (blockSize/32) * 8);
}

int main() {
 int blockSize = 256;
 int n = 1000000;
 int gridSize = (n + blockSize) / blockSize;

 printKernelStats(blockSize, gridSize);

 double a = 0.0, b = 1.0;
 double h = (b - a) / n;

 double *d_partial;
 cudaMalloc(&d_partial, gridSize * sizeof(double));

 // Benchmark each version
 cudaEvent_t start, stop;
 cudaEventCreate(&start);
 cudaEventCreate(&stop);

 // V1: Naive
 cudaEventRecord(start);
 trapKernelV1<<<gridSize, blockSize, blockSize*8>>>(a, h, n, d_partial);
 cudaEventRecord(stop);
 cudaEventSynchronize(stop);
 float v1_time;
 cudaEventElapsedTime(&v1_time, start, stop);

 // V2: Volatile
 cudaEventRecord(start);
 trapKernelV2<<<gridSize, blockSize, blockSize*8>>>(a, h, n, d_partial);
 cudaEventRecord(stop);
 cudaEventSynchronize(stop);
 float v2_time;
 cudaEventElapsedTime(&v2_time, start, stop);

 // V3: Warp Shuffle
 cudaEventRecord(start);
 trapKernelV3<<<gridSize, blockSize, (blockSize/32)*8>>>(a, h, n, d_partial);
 cudaEventRecord(stop);
 cudaEventSynchronize(stop);
 float v3_time;
 cudaEventElapsedTime(&v3_time, start, stop);

 printf("\nTiming Results:\n");
 printf("V1 (naive): %f ms\n", v1_time);
 printf("V2 (volatile): %f ms\n", v2_time);
 printf("V3 (shuffle): %f ms\n", v3_time);

 cudaFree(d_partial);
 return 0;
}
